#include <bits/stdc++.h>
using namespace std;
#define int long long

const int N = 5e5 + 10;
const int INF = 2e18;
int a[N]; 

struct Info {
    int sum, maxsum, maxl, maxr;
    Info operator+ (const Info &o) const {
        Info t;
        t.sum = sum + o.sum;
        t.maxsum = max({maxsum, o.maxsum, maxr + o.maxl});
        t.maxl = max(maxl, sum + o.maxl);
        t.maxr = max(o.maxr, maxr + o.sum);
        return t;
    }
} d[4 * N];

inline void push_up(int x) {
    d[x] = d[x * 2] + d[x * 2 + 1];
}

void build(int x, int l, int r) {
    if (l == r) {
        d[x] = {a[l], a[l], a[l], a[l]};
        return;
    }
    int mid = (l + r) >> 1;
    build(x * 2, l, mid);
    build(x * 2 + 1, mid + 1, r);
    push_up(x);
}

void update(int x, int l, int r, int pos, int v) { 
    if (l == r) {
        d[x] = {v, v, v, v};
        return;
    }
    int mid = (l + r) >> 1;
    if (pos <= mid) 
        update(x * 2, l, mid, pos, v);
    else
        update(x * 2 + 1, mid + 1, r, pos, v);
    push_up(x);
}

Info query(int x, int l, int r, int a, int b) {
    if (a <= l && r <= b) 
        return d[x];
    int mid = (l + r) >> 1;
    if (b <= mid) 
        return query(x * 2, l, mid, a, b);
    if (a > mid) 
        return query(x * 2 + 1, mid + 1, r, a, b);
    return query(x * 2, l, mid, a, b) + query(x * 2 + 1, mid + 1, r, a, b);
}

signed main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    int n, q;
    cin >> n >> q;
    for (int i = 1; i <= n; i++) 
        cin >> a[i];
    build(1, 1, n);
    while (q--) {
        int op, x, y;
        cin >> op >> x >> y;
        if(op == 1) {
            if(x > y) swap(x, y);
            cout << query(1, 1, n, x, y).maxsum << '\n';
        }
        else
            update(1, 1, n, x, y);
    }
    return 0;
}
